/* http://meyerweb.com/eric/tools/css/reset/ 
   v2.0 | 20110126
   License: none (public domain)
*/
@import 'https://fonts.googleapis.com/css?family=Sedgwick+Ave';
html, body, div, span, applet, object, iframe,
h1, h2, h3, h4, h5, h6, p, blockquote, pre,
a, abbr, acronym, address, big, cite, code,
del, dfn, em, img, ins, kbd, q, s, samp,
small, strike, strong, sub, sup, tt, var,
b, u, i, center,
dl, dt, dd, ol, ul, li,
fieldset, form, label, legend,
table, caption, tbody, tfoot, thead, tr, th, td,
article, aside, canvas, details, embed,
figure, figcaption, footer, header, hgroup,
menu, nav, output, ruby, section, summary,
time, mark, audio, video {
  margin: 0;
  padding: 0;
  border: 0;
  font-size: 100%;
  font: inherit;
  vertical-align: baseline;
}

/* HTML5 display-role reset for older browsers */
article, aside, details, figcaption, figure,
footer, header, hgroup, menu, nav, section {
  display: block;
}

body {
  line-height: 1;
}

ol, ul {
  list-style: none;
}

blockquote, q {
  quotes: none;
}

blockquote:before, blockquote:after,
q:before, q:after {
  content: "";
  content: none;
}

table {
  border-collapse: collapse;
  border-spacing: 0;
}

h1 {
  font-family: "Sedgwick Ave", "cursive";
  background: #0b9ef3;
  color: white;
  font-size: 60px;
  text-align: center;
  padding: 20px 0;
}

.display__weather {
  width: 50%;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1fr 1fr;
}
.display__weather h4, .display__weather #temperature {
  grid-column: span 2;
  margin-top: 20px;
  text-align: center;
  font-size: 30px;
  border-bottom: 2px solid gray;
}
.display__weather span {
  width: 100%;
  padding: 15px 0;
  text-align: center;
  font-size: 22px;
}
.display__weather #latitude, .display__weather #longitude {
  background: linear-gradient(white, rgba(138, 235, 248, 0.404));
}
.display__weather #minTemp, .display__weather #maxTemp {
  background: linear-gradient(rgba(165, 234, 243, 0.404), rgba(113, 222, 236, 0.404));
}
.display__weather #pressure, .display__weather #humidity {
  background: linear-gradient(rgba(113, 222, 236, 0.404), rgba(41, 208, 230, 0.404));
}

#searchPlace {
  display: block;
  text-align: center;
  outline: none;
  height: 30px;
  width: 50%;
  margin: 20px auto;
  border: 2px solid black;
  border-radius: 16px;
  padding: 5px 10px;
  font-size: 24px;
}

#search__city h4 {
  width: 50%;
  margin: 0 auto;
  border-bottom: 2px solid black;
  font-size: 30px;
  text-align: center;
}
